using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record ClassifyRequest(string Subject, string Description, float Priority);

public record ClassifyResponse(string PredictedCategory, float Confidence, Dictionary<string, float> Scores);

public class ModelMetadata
{
    public string[] Categories { get; init; } = [];
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class TicketModelTrainer
{
    public static string[] TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate for evaluation metrics (best approach for small datasets)
        Console.WriteLine("Training model with 3-fold cross-validation...");
        var cvResults = mlContext.MulticlassClassification.CrossValidate(
            data, pipeline, numberOfFolds: 3);

        Console.WriteLine("===== Cross-Validation Metrics (3-fold) =====");
        foreach (var (result, i) in cvResults.Select((r, i) => (r, i)))
        {
            Console.WriteLine(
                $"  Fold {i + 1}: MicroAccuracy={result.Metrics.MicroAccuracy:F4}, " +
                $"MacroAccuracy={result.Metrics.MacroAccuracy:F4}, " +
                $"LogLoss={result.Metrics.LogLoss:F4}");
        }

        var avgMicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgMacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);

        Console.WriteLine("  ─────────────────────────────────────────────");
        Console.WriteLine(
            $"  Average: MicroAccuracy={avgMicroAccuracy:F4}, " +
            $"MacroAccuracy={avgMacroAccuracy:F4}, " +
            $"LogLoss={avgLogLoss:F4}");
        Console.WriteLine();

        // Train final model on all data
        var model = pipeline.Fit(data);
        mlContext.Model.Save(model, data.Schema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");

        // Extract category labels from the trained model
        using var engine = mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
        var scoreColumn = engine.OutputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var categories = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        Console.WriteLine($"Categories: [{string.Join(", ", categories)}]");

        return categories;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly string[] _categories;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        ModelMetadata metadata)
    {
        _predictionPool = predictionPool;
        _categories = metadata.Categories;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        var scores = _categories
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => pair.Second);

        var response = new ClassifyResponse(
            prediction.Category,
            prediction.Score.Max(),
            scores);

        return Ok(response);
    }
}

