            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate for evaluation metrics (best approach for small datasets)
        Console.WriteLine("Training model with 3-fold cross-validation...");
        var cvResults = mlContext.MulticlassClassification.CrossValidate(
            data, pipeline, numberOfFolds: 3);

        Console.WriteLine("===== Cross-Validation Metrics (3-fold) =====");
        foreach (var (result, i) in cvResults.Select((r, i) => (r, i)))
        {
            Console.WriteLine(
                $"  Fold {i + 1}: MicroAccuracy={result.Metrics.MicroAccuracy:F4}, " +
                $"MacroAccuracy={result.Metrics.MacroAccuracy:F4}, " +
                $"LogLoss={result.Metrics.LogLoss:F4}");
        }

        var avgMicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgMacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);

        Console.WriteLine("  ─────────────────────────────────────────────");
        Console.WriteLine(
            $"  Average: MicroAccuracy={avgMicroAccuracy:F4}, " +
            $"MacroAccuracy={avgMacroAccuracy:F4}, " +
            $"LogLoss={avgLogLoss:F4}");
        Console.WriteLine();

        // Train final model on all data
        var model = pipeline.Fit(data);
        mlContext.Model.Save(model, data.Schema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");

        // Extract category labels from the trained model
        using var engine = mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
        var scoreColumn = engine.OutputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var categories = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        Console.WriteLine($"Categories: [{string.Join(", ", categories)}]");

        return categories;
    }
}

