var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train ML model at startup and print evaluation metrics
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");
var categories = TicketModelTrainer.TrainAndEvaluate(dataPath, modelPath);

// Register prediction engine pool (thread-safe) and model metadata
builder.Services.AddSingleton(new ModelMetadata { Categories = categories });
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

